import time
import random
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Any


# ── Session and interaction tracking ─────────────────────────────────────────
@dataclass
class AIInteraction:
    session_id: str
    request_id: str
    user_id: str
    prompt: str
    response: str
    model: str
    latency_ms: float
    cost_usd: float
    timestamp: float = field(default_factory=time.time)
    # User signals
    thumbs_up: bool | None = None
    thumbs_down: bool | None = None
    regenerated: bool = False
    copied: bool = False
    user_edited: bool = False
    # Quality signals
    quality_score: float | None = None  # LLM-as-judge, sampled
    safety_flag: bool = False

    @property
    def implicit_positive(self) -> bool:
        return self.copied or (self.thumbs_up is True)

    @property
    def implicit_negative(self) -> bool:
        return self.regenerated or (self.thumbs_down is True)

    @property
    def outcome(self) -> str:
        if self.implicit_positive:
            return 'positive'
        if self.implicit_negative:
            return 'negative'
        return 'neutral'


@dataclass
class Session:
    session_id: str
    user_id: str
    started_at: float = field(default_factory=time.time)
    interactions: list[AIInteraction] = field(default_factory=list)
    ended: bool = False

    def add(self, interaction: AIInteraction) -> None:
        self.interactions.append(interaction)

    @property
    def completed(self) -> bool:
        """Session is successful if at least one positive interaction occurred."""
        return any(i.implicit_positive for i in self.interactions)

    @property
    def depth(self) -> int:
        return len(self.interactions)

    @property
    def total_cost(self) -> float:
        return sum(i.cost_usd for i in self.interactions)


# ── AI Product Metrics Dashboard ──────────────────────────────────────────────
class AIProductMetrics:
    def __init__(self, window_hours: int = 24):
        self._window = window_hours * 3600
        self._sessions: list[Session] = []
        self._interactions: list[AIInteraction] = []

    def track_session(self, session: Session) -> None:
        self._sessions.append(session)
        self._interactions.extend(session.interactions)

    def _recent_sessions(self) -> list[Session]:
        cutoff = time.time() - self._window
        return [s for s in self._sessions if s.started_at >= cutoff]

    def _recent_interactions(self) -> list[AIInteraction]:
        cutoff = time.time() - self._window
        return [i for i in self._interactions if i.timestamp >= cutoff]

    def task_completion_rate(self) -> float:
        sessions = self._recent_sessions()
        if not sessions:
            return 0.0
        return sum(1 for s in sessions if s.completed) / len(sessions)

    def mean_csat(self) -> float | None:
        rated = [i for i in self._recent_interactions()
                 if i.thumbs_up is not None or i.thumbs_down is not None]
        if not rated:
            return None
        positive = sum(1 for i in rated if i.thumbs_up)
        return positive / len(rated)

    def regeneration_rate(self) -> float:
        interactions = self._recent_interactions()
        if not interactions:
            return 0.0
        return sum(1 for i in interactions if i.regenerated) / len(interactions)

    def mean_quality_score(self) -> float | None:
        scored = [i for i in self._recent_interactions() if i.quality_score is not None]
        if not scored:
            return None
        return sum(i.quality_score for i in scored) / len(scored)

    def cost_per_session(self) -> float:
        sessions = self._recent_sessions()
        if not sessions:
            return 0.0
        total = sum(s.total_cost for s in sessions)
        return total / len(sessions)

    def latency_percentile(self, p: float) -> float:
        latencies = [i.latency_ms for i in self._recent_interactions()]
        if not latencies:
            return 0.0
        s = sorted(latencies)
        idx = int(len(s) * p / 100)
        return s[min(idx, len(s) - 1)]

    def session_depth_distribution(self) -> dict[str, int]:
        sessions = self._recent_sessions()
        dist = {'1': 0, '2-3': 0, '4-10': 0, '10+': 0}
        for s in sessions:
            d = s.depth
            if d == 1:
                dist['1'] += 1
            elif d <= 3:
                dist['2-3'] += 1
            elif d <= 10:
                dist['4-10'] += 1
            else:
                dist['10+'] += 1
        return dist

    def report(self) -> dict:
        return {
            'window_hours': self._window // 3600,
            'total_sessions': len(self._recent_sessions()),
            'total_interactions': len(self._recent_interactions()),
            'task_completion_rate': round(self.task_completion_rate(), 3),
            'csat': round(self.mean_csat() or 0, 3),
            'regeneration_rate': round(self.regeneration_rate(), 3),
            'mean_quality_score': round(self.mean_quality_score() or 0, 3),
            'cost_per_session_usd': round(self.cost_per_session(), 5),
            'latency_p50_ms': round(self.latency_percentile(50), 1),
            'latency_p95_ms': round(self.latency_percentile(95), 1),
            'session_depth_distribution': self.session_depth_distribution(),
        }


# ── Product health check ──────────────────────────────────────────────────────
class AIProductHealthCheck:
    THRESHOLDS = {
        'task_completion_rate': (0.6, 'min'),   # must be >= 60%
        'csat': (0.7, 'min'),                    # must be >= 70% positive
        'regeneration_rate': (0.15, 'max'),      # must be <= 15%
        'mean_quality_score': (0.7, 'min'),      # must be >= 0.70
        'latency_p95_ms': (3000, 'max'),         # must be <= 3000ms
    }

    def check(self, metrics: dict) -> dict:
        results = {}
        overall_healthy = True
        for metric, (threshold, direction) in self.THRESHOLDS.items():
            value = metrics.get(metric, 0)
            if direction == 'min':
                ok = value >= threshold
            else:
                ok = value <= threshold
            results[metric] = {'value': value, 'threshold': threshold, 'ok': ok}
            if not ok:
                overall_healthy = False

        return {
            'healthy': overall_healthy,
            'metrics': results,
            'recommendation': 'Ship' if overall_healthy else 'Hold — fix failing gates first',
        }


# ── Demo ──────────────────────────────────────────────────────────────────────
if __name__ == '__main__':
    random.seed(42)
    dashboard = AIProductMetrics(window_hours=24)
    health = AIProductHealthCheck()

    # Simulate 200 sessions
    for i in range(200):
        session = Session(session_id=f's{i}', user_id=f'u{i % 50}')
        n_interactions = random.randint(1, 6)
        for j in range(n_interactions):
            interaction = AIInteraction(
                session_id=session.session_id,
                request_id=f'r{i}_{j}',
                user_id=session.user_id,
                prompt=f'Question {j}',
                response='Model response...',
                model=random.choice(['gpt-4o-mini', 'gpt-4o']),
                latency_ms=random.gauss(800, 300),
                cost_usd=random.uniform(0.0001, 0.002),
                thumbs_up=random.choice([True, False, None, None]),
                thumbs_down=random.choice([False, True, None, None]),
                regenerated=random.random() < 0.10,
                copied=random.random() < 0.35,
                quality_score=random.uniform(0.6, 0.95) if random.random() < 0.1 else None,
            )
            session.add(interaction)
        dashboard.track_session(session)

    report = dashboard.report()
    print('=== AI Product Metrics Dashboard ===')
    for k, v in report.items():
        print(f'  {k}: {v}')

    print('\n=== Product Health Check ===')
    health_result = health.check(report)
    print(f'Overall: {"HEALTHY" if health_result["healthy"] else "UNHEALTHY"}')
    print(f'Recommendation: {health_result["recommendation"]}')
    for metric, data in health_result['metrics'].items():
        status = 'OK' if data['ok'] else 'FAIL'
        print(f'  [{status}] {metric}: {data["value"]} (threshold: {data["threshold"]})')
